(()=>{const b=()=>{document.querySelectorAll('*').forEach(e=>{for(const a of e.attributes){if(a.name.startsWith('hx-on:')&&!e.dataset.hxBound){const t=a.name.split(':')[1],c=a.value;e.addEventListener(t,r=>{new Function('event',c).call(e,r)});}}e.dataset.hxBound='1';});};document.addEventListener('DOMContentLoaded',b);window.htmx={process:b};})();
